using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using GTA.Native;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        private LiveStudioClient _client;

        private enum MissionState { Idle, Active }
        private MissionState _state = MissionState.Idle;

        private Vehicle _missionVehicle;
        private Vector3 _destinationPosition;
        private Blip _destinationBlip;
        private DateTime _missionStartTime;
        private readonly TimeSpan _missionTimeLimit = TimeSpan.FromMinutes(10);

        private readonly Dictionary<string, DateTime> _cooldowns = new Dictionary<string, DateTime>();

        private readonly List<Vehicle> _spawnedPursuers = new List<Vehicle>();
        private readonly List<Vehicle> _spawnedEscorts = new List<Vehicle>();
        private readonly List<Ped> _spawnedPeds = new List<Ped>();

        private Blip _detourBlip;
        private Vector3 _detourPosition;
        private bool _detourActive;

        private bool _bulletproofActive;
        private DateTime _bulletproofEndTime;

        private bool _speedBoostActive;
        private DateTime _speedBoostEndTime;

        private bool _engineStallActive;
        private DateTime _engineStallEndTime;

        private bool _tractionReduced;
        private DateTime _tractionEndTime;
        private float _originalTractionMultiplier = 1.0f;

        private readonly Random _random = new Random();

        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();
        }

        private void HandleEvent(LiveStudioEvent evt)
        {
            if (evt is ChatEvent chat)
            {
                HandleChatEvent(chat);
            }
            else if (evt is GiftEvent gift)
            {
                // Gift IDs are unresolved – no GiftId comparisons.
            }
        }

        private void HandleChatEvent(ChatEvent chat)
        {
            string content = chat.Content?.Trim().ToLower();
            if (string.IsNullOrEmpty(content)) return;

            MainThreadDispatcher.Enqueue(() => ProcessChatCommand(content));
        }

        private void ProcessChatCommand(string content)
        {
            if (!content.StartsWith("!")) return;

            string[] parts = content.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
            if (parts.Length == 0) return;
            string command = parts[0];

            switch (command)
            {
                case "!startfragile":
                    StartMission();
                    break;
                case "!repair25":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!repair25", TimeSpan.FromSeconds(30))) return;
                    ApplyRepair25();
                    break;
                case "!bulletproof":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!bulletproof", TimeSpan.FromSeconds(0))) return;
                    ApplyBulletproof();
                    break;
                case "!clearpursuers":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!clearpursuers", TimeSpan.FromSeconds(60))) return;
                    ClearPursuers();
                    break;
                case "!speedboost":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!speedboost", TimeSpan.FromSeconds(30))) return;
                    ApplySpeedBoost();
                    break;
                case "!escort":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!escort", TimeSpan.FromSeconds(60))) return;
                    SpawnEscort();
                    break;
                case "!flattire":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!flattire", TimeSpan.FromSeconds(10))) return;
                    ApplyFlatTire();
                    break;
                case "!enginestall":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!enginestall", TimeSpan.FromSeconds(10))) return;
                    ApplyEngineStall();
                    break;
                case "!spawnpursuit":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!spawnpursuit", TimeSpan.FromSeconds(30))) return;
                    SpawnPursuit();
                    break;
                case "!reducetraction":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!reducetraction", TimeSpan.FromSeconds(15))) return;
                    ApplyReducedTraction();
                    break;
                case "!nearbyexplosion":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!nearbyexplosion", TimeSpan.FromSeconds(15))) return;
                    ApplyNearbyExplosion();
                    break;
                case "!detour":
                    if (_state != MissionState.Active) return;
                    if (!CheckCooldown("!detour", TimeSpan.FromSeconds(60))) return;
                    ApplyDetour();
                    break;
            }
        }

        private bool CheckCooldown(string command, TimeSpan cooldown)
        {
            if (_cooldowns.TryGetValue(command, out DateTime lastUsed))
            {
                if (DateTime.UtcNow - lastUsed < cooldown)
                    return false;
            }
            _cooldowns[command] = DateTime.UtcNow;
            return true;
        }

        private void StartMission()
        {
            if (_state == MissionState.Active)
            {
                GTA.UI.Screen.ShowSubtitle("~y~A mission is already active.");
                return;
            }

            Ped playerPed = Game.Player.Character;
            if (!playerPed.IsInVehicle())
            {
                GTA.UI.Screen.ShowSubtitle("~y~You must be in a vehicle to start the delivery.");
                return;
            }

            Vehicle vehicle = playerPed.CurrentVehicle;
            if (vehicle == null || !vehicle.Exists() || vehicle.Health < 200)
            {
                GTA.UI.Screen.ShowSubtitle("~y~Your vehicle is too damaged. Repair it first.");
                return;
            }

            _missionVehicle = vehicle;
            _missionVehicle.CanTiresBurst = true;
            _missionVehicle.EnginePowerMultiplier = 1.0f;
            _missionVehicle.TractionMultiplier = 1.0f;
            _originalTractionMultiplier = _missionVehicle.TractionMultiplier;

            Vector3 playerPos = playerPed.Position;
            Vector3 randomOffset = new Vector3(
                (float)(_random.NextDouble() * 6000 - 3000),
                (float)(_random.NextDouble() * 6000 - 3000),
                0f
            );
            Vector3 targetPos = playerPos + randomOffset;
            _destinationPosition = World.GetNextPositionOnStreet(targetPos);

            _destinationBlip = World.CreateBlip(_destinationPosition);
            _destinationBlip.Sprite = BlipSprite.Standard;
            _destinationBlip.Color = BlipColor.Yellow;
            _destinationBlip.Name = "Delivery Point";
            _destinationBlip.IsShortRange = false;

            _missionStartTime = DateTime.UtcNow;
            _state = MissionState.Active;

            GTA.UI.Notification.Show("~g~Fragile Cargo Delivery started! Reach the yellow marker within 10 minutes.");
            GTA.UI.Screen.ShowSubtitle("~g~Delivery started. 10 minutes on the clock.");
        }

        private void ApplyRepair25()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            int maxHealth = _missionVehicle.MaxHealth;
            if (_missionVehicle.Health >= maxHealth)
            {
                GTA.UI.Screen.ShowSubtitle("~y~Vehicle is already at full health.");
                return;
            }

            int healAmount = (int)(maxHealth * 0.25f);
            _missionVehicle.Health = Math.Min(_missionVehicle.Health + healAmount, maxHealth);
            GTA.UI.Screen.ShowSubtitle("~g~Vehicle repaired 25%!");
        }

        private void ApplyBulletproof()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            TimeSpan maxDuration = TimeSpan.FromSeconds(30);
            DateTime now = DateTime.UtcNow;

            if (_bulletproofActive && now < _bulletproofEndTime)
            {
                DateTime newEnd = _bulletproofEndTime + TimeSpan.FromSeconds(30);
                DateTime cap = now + maxDuration;
                _bulletproofEndTime = newEnd < cap ? newEnd : cap;
            }
            else
            {
                _missionVehicle.CanTiresBurst = false;
                _bulletproofActive = true;
                _bulletproofEndTime = now + TimeSpan.FromSeconds(30);
            }

            GTA.UI.Screen.ShowSubtitle("~g~Bulletproof tires active!");
        }

        private void ClearPursuers()
        {
            foreach (Vehicle v in _spawnedPursuers)
            {
                if (v != null && v.Exists())
                {
                    v.Delete();
                }
            }
            _spawnedPursuers.Clear();

            for (int i = _spawnedPeds.Count - 1; i >= 0; i--)
            {
                Ped p = _spawnedPeds[i];
                if (p == null || !p.Exists() || !p.IsInVehicle())
                {
                    if (p != null && p.Exists()) p.Delete();
                    _spawnedPeds.RemoveAt(i);
                }
            }

            GTA.UI.Screen.ShowSubtitle("~g~All pursuers cleared!");
        }

        private void ApplySpeedBoost()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            if (_speedBoostActive && DateTime.UtcNow < _speedBoostEndTime)
            {
                GTA.UI.Screen.ShowSubtitle("~y~Speed boost already active.");
                return;
            }

            _missionVehicle.EnginePowerMultiplier = 2.0f;
            _speedBoostActive = true;
            _speedBoostEndTime = DateTime.UtcNow + TimeSpan.FromSeconds(5);

            GTA.UI.Screen.ShowSubtitle("~g~Speed boost for 5 seconds!");
        }

        private void SpawnEscort()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            if (_spawnedEscorts.Count >= 2)
            {
                GTA.UI.Screen.ShowSubtitle("~y~Maximum escorts (2) already active.");
                return;
            }

            Vector3 spawnPos = _missionVehicle.Position + _missionVehicle.ForwardVector * -15f;
            Vector3 streetPos = World.GetNextPositionOnStreet(spawnPos);

            Vehicle escortVehicle = CreateVehicle("police", streetPos, _missionVehicle.Heading);
            if (escortVehicle == null)
            {
                GTA.UI.Screen.ShowSubtitle("~y~Failed to spawn escort vehicle.");
                return;
            }

            Ped escortPed = CreatePed("s_m_y_cop_01", streetPos);
            if (escortPed == null)
            {
                escortVehicle.Delete();
                GTA.UI.Screen.ShowSubtitle("~y~Failed to spawn escort driver.");
                return;
            }

            escortPed.SetIntoVehicle(escortVehicle, VehicleSeat.Driver);
            escortPed.RelationshipGroup = Game.Player.Character.RelationshipGroup;

            Function.Call(Hash.TASK_VEHICLE_DRIVE_TO_COORD_LONGRANGE,
                escortPed, escortVehicle,
                _destinationPosition.X, _destinationPosition.Y, _destinationPosition.Z,
                25f, 786603, 5f);

            _spawnedEscorts.Add(escortVehicle);
            _spawnedPeds.Add(escortPed);

            GTA.UI.Screen.ShowSubtitle("~g~Escort vehicle spawned!");
        }

        private void ApplyFlatTire()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            int wheelCount = _missionVehicle.Wheels.Count;
            List<int> intactWheels = new List<int>();
            for (int i = 0; i < wheelCount; i++)
            {
                bool burst = Function.Call<bool>(Hash.IS_VEHICLE_TYRE_BURST, _missionVehicle.Handle, i, false);
                if (!burst)
                {
                    intactWheels.Add(i);
                }
            }

            if (intactWheels.Count == 0)
            {
                GTA.UI.Screen.ShowSubtitle("~y~All tires are already burst!");
                return;
            }

            int tireIndex = intactWheels[_random.Next(intactWheels.Count)];
            Function.Call(Hash.SET_VEHICLE_TYRE_BURST, _missionVehicle.Handle, tireIndex, true, 1000f);

            GTA.UI.Screen.ShowSubtitle("~r~Tire burst!");
        }

        private void ApplyEngineStall()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            _missionVehicle.IsEngineRunning = false;

            DateTime now = DateTime.UtcNow;
            if (_engineStallActive && now < _engineStallEndTime)
            {
                _engineStallEndTime = _engineStallEndTime + TimeSpan.FromSeconds(3);
            }
            else
            {
                _engineStallActive = true;
                _engineStallEndTime = now + TimeSpan.FromSeconds(3);
            }

            GTA.UI.Screen.ShowSubtitle("~r~Engine stalled!");
        }

        private void SpawnPursuit()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            if (_spawnedPursuers.Count >= 4)
            {
                GTA.UI.Screen.ShowSubtitle("~y~Maximum pursuers (4) already active.");
                return;
            }

            Vector3 spawnPos = _missionVehicle.Position + _missionVehicle.ForwardVector * -30f;
            Vector3 streetPos = World.GetNextPositionOnStreet(spawnPos);

            string[] pursuitModels = { "sultan", "futo", "ruiner", "penumbra" };
            string modelName = pursuitModels[_random.Next(pursuitModels.Length)];

            Vehicle pursuitVehicle = CreateVehicle(modelName, streetPos, _missionVehicle.Heading);
            if (pursuitVehicle == null)
            {
                GTA.UI.Screen.ShowSubtitle("~y~Failed to spawn pursuit vehicle.");
                return;
            }

            Ped pursuitPed = CreatePed("s_m_y_swat_01", streetPos);
            if (pursuitPed == null)
            {
                pursuitVehicle.Delete();
                GTA.UI.Screen.ShowSubtitle("~y~Failed to spawn pursuit driver.");
                return;
            }

            pursuitPed.SetIntoVehicle(pursuitVehicle, VehicleSeat.Driver);
            pursuitPed.Task.CombatPed(Game.Player.Character);

            _spawnedPursuers.Add(pursuitVehicle);
            _spawnedPeds.Add(pursuitPed);

            GTA.UI.Screen.ShowSubtitle("~r~Pursuit vehicle incoming!");
        }

        private void ApplyReducedTraction()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            DateTime now = DateTime.UtcNow;
            if (_tractionReduced && now < _tractionEndTime)
            {
                _tractionEndTime = _tractionEndTime + TimeSpan.FromSeconds(5);
            }
            else
            {
                _originalTractionMultiplier = _missionVehicle.TractionMultiplier;
                _missionVehicle.TractionMultiplier = _originalTractionMultiplier * 0.5f;
                _tractionReduced = true;
                _tractionEndTime = now + TimeSpan.FromSeconds(5);
            }

            GTA.UI.Screen.ShowSubtitle("~r~Traction reduced!");
        }

        private void ApplyNearbyExplosion()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            Vector3 vehPos = _missionVehicle.Position;
            float angle = (float)(_random.NextDouble() * Math.PI * 2);
            Vector3 explosionPos = vehPos + new Vector3(
                (float)Math.Cos(angle) * 2f,
                (float)Math.Sin(angle) * 2f,
                0f
            );

            Function.Call(Hash.ADD_EXPLOSION,
                explosionPos.X, explosionPos.Y, explosionPos.Z,
                1,
                1.0f, true, false, 1.0f);

            if (_missionVehicle.Exists())
            {
                _missionVehicle.Health = Math.Max(_missionVehicle.Health, 150);
            }

            GTA.UI.Screen.ShowSubtitle("~r~Explosion nearby!");
        }

        private void ApplyDetour()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            if (_detourActive)
            {
                GTA.UI.Screen.ShowSubtitle("~y~A detour checkpoint is already active.");
                return;
            }

            Vector3 currentPos = _missionVehicle.Position;
            float t = 0.4f + (float)(_random.NextDouble() * 0.3f);
            Vector3 midPoint = currentPos + (_destinationPosition - currentPos) * t;
            Vector3 offset = new Vector3(
                (float)(_random.NextDouble() * 400 - 200),
                (float)(_random.NextDouble() * 400 - 200),
                0f
            );
            _detourPosition = World.GetNextPositionOnStreet(midPoint + offset);

            _detourBlip = World.CreateBlip(_detourPosition);
            _detourBlip.Sprite = BlipSprite.Waypoint;
            _detourBlip.Color = BlipColor.Orange;
            _detourBlip.Name = "Detour Checkpoint";
            _detourBlip.IsShortRange = false;

            _detourActive = true;

            GTA.UI.Screen.ShowSubtitle("~r~Detour checkpoint added! Visit the orange marker.");
        }

        private Vehicle CreateVehicle(string modelName, Vector3 position, float heading)
        {
            Model model = new Model(modelName);
            model.Request();
            if (!model.IsLoaded)
            {
                model.MarkAsNoLongerNeeded();
                return null;
            }

            Vehicle vehicle = World.CreateVehicle(model, position, heading);
            model.MarkAsNoLongerNeeded();
            return vehicle;
        }

        private Ped CreatePed(string modelName, Vector3 position)
        {
            Model model = new Model(modelName);
            model.Request();
            if (!model.IsLoaded)
            {
                model.MarkAsNoLongerNeeded();
                return null;
            }

            Ped ped = World.CreatePed(model, position);
            model.MarkAsNoLongerNeeded();
            return ped;
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();

            if (_state != MissionState.Active) return;

            Ped playerPed = Game.Player.Character;

            if (!playerPed.IsInVehicle() || playerPed.CurrentVehicle != _missionVehicle)
            {
                FailMission("You left the delivery vehicle!");
                return;
            }

            if (_missionVehicle == null || !_missionVehicle.Exists() || _missionVehicle.IsDead)
            {
                FailMission("The delivery vehicle was destroyed!");
                return;
            }

            if (DateTime.UtcNow - _missionStartTime > _missionTimeLimit)
            {
                FailMission("Time's up! Delivery failed.");
                return;
            }

            if (_missionVehicle.Position.DistanceTo(_destinationPosition) < 15f)
            {
                SucceedMission();
                return;
            }

            if (_detourActive && _missionVehicle.Position.DistanceTo(_detourPosition) < 25f)
            {
                if (_detourBlip != null && _detourBlip.Exists())
                {
                    Function.Call(Hash.REMOVE_BLIP, _detourBlip.Handle);
                    _detourBlip = null;
                }
                _detourActive = false;
                GTA.UI.Screen.ShowSubtitle("~g~Detour checkpoint visited!");
            }

            DateTime now = DateTime.UtcNow;

            if (_bulletproofActive && now >= _bulletproofEndTime)
            {
                if (_missionVehicle != null && _missionVehicle.Exists())
                {
                    _missionVehicle.CanTiresBurst = true;
                }
                _bulletproofActive = false;
            }

            if (_speedBoostActive && now >= _speedBoostEndTime)
            {
                if (_missionVehicle != null && _missionVehicle.Exists())
                {
                    _missionVehicle.EnginePowerMultiplier = 1.0f;
                }
                _speedBoostActive = false;
            }

            if (_engineStallActive && now >= _engineStallEndTime)
            {
                if (_missionVehicle != null && _missionVehicle.Exists())
                {
                    _missionVehicle.IsEngineRunning = true;
                }
                _engineStallActive = false;
            }

            if (_tractionReduced && now >= _tractionEndTime)
            {
                if (_missionVehicle != null && _missionVehicle.Exists())
                {
                    _missionVehicle.TractionMultiplier = _originalTractionMultiplier;
                }
                _tractionReduced = false;
            }
        }

        private void SucceedMission()
        {
            GTA.UI.Notification.Show("~g~Delivery complete! Cargo delivered successfully.");
            GTA.UI.Screen.ShowSubtitle("~g~Delivery successful!");

            CleanupMission();
        }

        private void FailMission(string reason)
        {
            GTA.UI.Notification.Show("~r~" + reason);
            GTA.UI.Screen.ShowSubtitle("~r~" + reason);

            CleanupMission();
        }

        private void CleanupMission()
        {
            if (_destinationBlip != null && _destinationBlip.Exists())
            {
                Function.Call(Hash.REMOVE_BLIP, _destinationBlip.Handle);
                _destinationBlip = null;
            }

            if (_detourBlip != null && _detourBlip.Exists())
            {
                Function.Call(Hash.REMOVE_BLIP, _detourBlip.Handle);
                _detourBlip = null;
                _detourActive = false;
            }

            foreach (Vehicle v in _spawnedPursuers)
            {
                if (v != null && v.Exists())
                {
                    v.Delete();
                }
            }
            _spawnedPursuers.Clear();

            foreach (Vehicle v in _spawnedEscorts)
            {
                if (v != null && v.Exists())
                {
                    v.Delete();
                }
            }
            _spawnedEscorts.Clear();

            foreach (Ped p in _spawnedPeds)
            {
                if (p != null && p.Exists())
                {
                    p.Delete();
                }
            }
            _spawnedPeds.Clear();

            if (_missionVehicle != null && _missionVehicle.Exists())
            {
                _missionVehicle.CanTiresBurst = true;
                _missionVehicle.EnginePowerMultiplier = 1.0f;
                _missionVehicle.TractionMultiplier = _originalTractionMultiplier;
                _missionVehicle.IsEngineRunning = true;
            }

            _bulletproofActive = false;
            _speedBoostActive = false;
            _engineStallActive = false;
            _tractionReduced = false;

            _state = MissionState.Idle;
        }

        private void OnAborted(object sender, EventArgs e)
        {
            CleanupMission();
            _client?.Dispose();
        }
    }
}
